import CustomCard from "@/components/Card/CustomCard";
import { apiBaseUrl } from "@/config";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import { useUserStore } from "@/stores/userStore";
import { DestinationAddress } from "@/types";
import { PencilIcon, TrashIcon } from "@heroicons/react/24/outline";
import React, { useEffect } from "react";
import Cookies from "js-cookie";
import Spinner from "@/components/Loading/Spinner";

const SavedAddress = () => {
  const userId = Cookies.get("userId");

  const destAddress = useCustomSWR<DestinationAddress>(
    userId ? `${apiBaseUrl}/destinationAddress/${parseInt(userId) - 1}` : null
  );

  useEffect(() => {
    useUserStore.persist.rehydrate();
  }, []);
  return (
    <div className="flex flex-col">
      <div className="bg-primary w-full py-12 px-4 md:px-[5%] lg:px-[12%]">
        <h1 className="text-3xl font-semibold text-white">Saved Address</h1>
      </div>
      <div className="py-10 flex flex-col gap-8 px-4 md:px-[5%] lg:px-[12%] items-center">
        {destAddress.error && (
          <div>
            There is something wrong when getting the data, please refresh the
            page.
          </div>
        )}
        {/* {destAddress.isLoading && <Spinner />} */}
        {destAddress.data ? (
          destAddress.data.address.map((item, idx) => (
            <div key={idx}>
              <CustomCard cardTitle={item.addressName}>
                <div className="flex absolute top-5 right-5">
                  <button className="p-2" onClick={() => {}}>
                    <PencilIcon
                      width={28}
                      height={28}
                      className="text-primary"
                    />
                  </button>
                  <button className="p-2" onClick={() => {}}>
                    <TrashIcon width={28} height={28} className="text-error" />
                  </button>
                </div>
                <table className="mt-2 border-separate border-spacing-2">
                  <tbody>
                    <tr>
                      <td className="font-semibold">Receiver Name</td>
                      <td>: {item.receiver}</td>
                    </tr>
                    <tr>
                      <td>Receiver Phone Number</td>
                      <td>: {item.receiverPhone}</td>
                    </tr>
                    <tr>
                      <td>Street</td>
                      <td>: {item.street}</td>
                    </tr>
                    <tr>
                      <td>City</td>
                      <td>: {item.city}</td>
                    </tr>
                    <tr>
                      <td>Province</td>
                      <td>: {item.province}</td>
                    </tr>
                  </tbody>
                </table>
              </CustomCard>
            </div>
          ))
        ) : (
          <Spinner />
        )}
      </div>
    </div>
  );
};

export default SavedAddress;
